    VALUES ('tahsili', 'فيزياء', 'كم', 'اختيار من متعدد', 'في معادلة دي بروي λ = h/(mv) فإن λ تمثّل:', '["طاقة الموجة", "سعة الموجة", "تردد الموجة", "طول الموجة"]'::jsonb, 3, 'معادلة دي بروي تربط الطول الموجي للجسيم بـبالـ Planck والكتلة والسرعة.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'بصريات', 'اختيار من متعدد', 'صفة تميّز الصور الحقيقية في العدسات:', '["مقلوبة", "معتدلة", "مساوية للجسم", "مصغّرة جداً"]'::jsonb, 0, 'الصور الحقيقية (المتكوّنة على شاشة) عبر العدسات المحدّبة دائماً مقلوبة.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'حركة', 'اختيار من متعدد', 'يتحرك قطار بسرعة 30 m/s، لو تباطأ بمعدل 3 m/s² حتى توقّف، فإن المسافة اللازمة حتى يتوقّف تماماً هي:', '["50 m", "100 m", "150 m", "750 m"]'::jsonb, 2, 'باستخدام v² = u² − 2as. عند التوقف v=0: 0 = 900 − 6s → s = 150 m.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'حركة', 'اختيار من متعدد', 'دراجة تبدأ حركتها من السكون، وتتحرك نزولاً إلى أسفل منحدر بتسارع ثابت 5 m/s²، وبعد 5 ثوانٍ تصل الدراجة إلى أسفل المنحدر وتكون سرعتها:', '["1 m/s", "25 m/s", "12.5 m/s", "50 m/s"]'::jsonb, 1, 'v = u + at = 0 + 5·5 = 25 m/s.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'بصريات', 'اختيار من متعدد', 'معدل أبعاد الطاقة الضوئية من المصدر المضيء؟', '["شدة الإضاءة", "الإضاءة", "التدفّق الضوئي", "الاستضاءة"]'::jsonb, 2, 'التدفّق الضوئي = إجمالي الطاقة الضوئية المنبعثة من المصدر في كل الاتجاهات.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'حركة', 'اختيار من متعدد', 'ذهب محمد من الشرق إلى الغرب 20 m وعاد للشرق 15 m. احسب المسافة والإزاحة.', '["المسافة 35 m والإزاحة 5 m", "المسافة 5 m والإزاحة 35 m", "المسافة 35 m والإزاحة 35 m", "المسافة 35 m والإزاحة 0 m"]'::jsonb, 0, 'المسافة = مجموع الطرق المقطوعة = 20+15 = 35. الإزاحة = الفرق المحصّل = 20−15 = 5 m.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'كهرباء', 'اختيار من متعدد', 'شحنة A تساوي −3 كولوم وشحنة B عبارة عن 3 ملايين ضعف شحنة الإلكترون، فإن شحنة الإلكترون C = 1.6 × 10⁻¹⁹. ما العلاقة بين |A| و |B|؟', '["أكبر", "مساوية", "أقل", "تعتمد على درجة الحرارة"]'::jsonb, 0, '|A| = 3 C. |B| = 3×10⁶ × 1.6×10⁻¹⁹ ≈ 4.8×10⁻¹³ C. |A| أكبر بكثير.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'كهرباء', 'اختيار من متعدد', 'حسب قانون كولوم فإن القوة الكهربائية F تناسب مع المسافة بين الشحنتين r حسب العلاقة:', '["F ∝ 1/r", "F ∝ 1/r²", "F ∝ r", "F ∝ r²"]'::jsonb, 1, 'قانون كولوم: F = kq₁q₂/r². القوة تتناسب عكسياً مع مربع المسافة.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'حركة', 'اختيار من متعدد', 'أي التالي يصف قوّتا زوج التأثير المتبادل؟', '["متفقان في المقدار والاتجاه", "متفقان في المقدار مختلفان في الاتجاه", "مختلفان في المقدار متفقان في الاتجاه", "مختلفان في المقدار والاتجاه"]'::jsonb, 1, 'قانون نيوتن الثالث: لكل فعل ردّ فعل مساوٍ في المقدار ومعاكس في الاتجاه.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'فيزياء نووية', 'اختيار من متعدد', 'ما الذي يؤثّر في صرونة المادة الصلبة؟', '["القوة الميكانيكية", "القوة الكهربائية", "القوة الكهرومغناطيسية", "القوة النووية"]'::jsonb, 2, 'الترابط الذرّي في المواد الصلبة ناتج عن القوة الكهرومغناطيسية بين الإلكترونات والنوى.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'شغل وطاقة', 'اختيار من متعدد', 'إذا كان الشغل الناتج لآلة يساوي ثلث أرباع الشغل المبذول، فاحسب الكفاءة.', '["15%", "25%", "50%", "75%"]'::jsonb, 3, 'الكفاءة = الشغل الناتج / الشغل المبذول × 100 = (3/4) × 100 = 75%.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'كم', 'اختيار من متعدد', 'الانبعاث التلقائي هو:', '["انتقال الذرة المُثارة إلى الحالة المستقرة باعثةً فوتوناً طاقته تساوي فرق الامتصاص", "انتقال الذرة المستقرة إلى الحالة المُثارة باعثةً فوتوناً", "انتقال الذرة المُثارة إلى الحالة المستقرة دون فقد أو امتصاص فوتونات", "انتقال الذرة المُثارة إلى الحالة المستقرة دون فقد أو امتصاص فوتونات"]'::jsonb, 0, 'الانبعاث التلقائي: الذرة في حالة مُثارة تنزل إلى مستوى أدنى وتطلق فوتوناً طاقته = فرق الطاقتين.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'موجات', 'اختيار من متعدد', 'أصغر طول للعمود الهوائي المغلق يكون عند:', '["λ/4", "λ/2", "2λ", "4λ"]'::jsonb, 0, 'العمود الهوائي المغلق من طرف واحد: الموجة الأساسية بطول λ/4.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'نسبية', 'اختيار من متعدد', 'وفق نظرية أينشتاين: الضوء ينحرف عند مروره بجانب:', '["كتلة كبيرة جداً", "كتلة صغيرة جداً", "كتلة كبيرة جداً (مكرر)", "كتلة صغيرة جداً (مكرر)"]'::jsonb, 0, 'وفقاً للنسبية العامة: الجاذبية القوية (الكتلة الكبيرة) تحني نسيج الزمكان فينحرف الضوء.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'قوى', 'اختيار من متعدد', 'إذا تم شد جسم لأعلى وكانت قوة الوزن mg فإن القوة العمودية:', '["مساوية لها", "أكبر منها", "أصغر منها", "ضعفها"]'::jsonb, 2, 'عند الشدّ لأعلى، القوة العمودية = mg − F_شد (أقل من الوزن).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'موجات', 'اختيار من متعدد', 'صدى الصوت هو ظاهرة فيزيائية ناتجة عن:', '["الحيود", "التداخل", "الانعكاس", "الانكسار"]'::jsonb, 2, 'الصدى = انعكاس الموجات الصوتية عن سطح بعيد ثم عودتها للأذن.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'كهرومغناطيسية', 'اختيار من متعدد', 'يتحرك سلك مستقيم بسرعة 2 m/s عمودياً على مجال مغناطيسي منتظم شدّته 0.2 T، فتولّدت فيه قوة دافعة حثّية مقدارها 0.2 V. إذا طول السلك L، يساوي:', '["0.1", "0.3", "0.5", "0.7"]'::jsonb, 2, 'emf = BLv → 0.2 = 0.2·L·2 → L = 0.5 m.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'حركة دورانية', 'اختيار من متعدد', 'إذا كان عزم دوران باب 150 N·m وطوله 50 cm، فأوجد القوة بالوحدات الدولية.', '["150", "300", "600", "750"]'::jsonb, 2, 'τ = F·d. 50 cm = 0.5 m. F = τ/d = 150/0.25 = 600 N (مع ذراع نصف الباب).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'شغل وطاقة', 'اختيار من متعدد', 'احسب القدرة التي دفع صندوقاً كتلته 5 kg لمسافة 50 m لمدة 5 ثوانٍ. (g = 10 m/s²)', '["125 W", "250 W", "500 W", "1000 W"]'::jsonb, 2, 'الشغل ضد الجاذبية لرفع 50 m: W = mgh = 5·10·50 = 2500 J. القدرة = W/t = 2500/5 = 500 W.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'شغل وطاقة', 'اختيار من متعدد', 'طبقاً لنظرية (الشغل-الطاقة) ΔKE = W، فإذا بذل المحيط الخارجي شغلاً من صندوق متحرك أفقياً على سطح أملس فإن الطاقة الحركية للصندوق:', '["تقل", "تثبت", "تذبذب", "تزيد"]'::jsonb, 3, 'إضافة شغل موجب من المحيط = إضافة طاقة حركية → ΔKE موجب → الطاقة الحركية تزيد.', grp_id, NULL, false, 'active', false);
