    VALUES ('tahsili', 'كيمياء', 'محاليل', 'اختيار من متعدد', 'الزيت يذوب في:', '["H₂O", "CH₃OCH₃", "CH₃CH₂COOH", "CH₂OH"]'::jsonb, 1, 'الزيت غير قطبي. CH₃OCH₃ (ثنائي ميثيل إيثر) قطبية ضعيفة، أنسب لإذابة الزيت من باقي المركّبات القطبية.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'محاليل', 'اختيار من متعدد', 'محلول قياسي من H₂SO₄ تركيزه 2 M وحجمه 0.5 L. إذا خُفّف لـ1 L، فإن كتلة H₂SO₄ في المحلول تساوي: (H=1, S=32, O=16)', '["24.5 g", "49 g", "98 g", "196 g"]'::jsonb, 2, 'عدد المولات = M·V = 2·0.5 = 1 mol. الكتلة المولية H₂SO₄ = 98. الكتلة = 1·98 = 98 g.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'كيمياء عضوية', 'اختيار من متعدد', 'أي التالي ينتج عن استبدال مجموعة الهيدروكسيل (-OH) بذرة نيتروجين مرتبطة بروابط أخرى في الأحماض الكربوكسيلية؟', '["الأميدات", "كيتون", "الأحماض الأمينية", "حموض كربوكسيلية"]'::jsonb, 0, 'استبدال -OH بـ-NH₂ في الكربوكسيل (-COOH) ينتج الأميد (-CONH₂).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'كيمياء عامة', 'اختيار من متعدد', 'أي الخواص التالية يمثّل خاصية فيزيائية؟', '["تكوّن صدأ الحديد", "احتراق قطعة خشب", "فقد الفضة بريقها", "توصيل النحاس للكهرباء"]'::jsonb, 3, 'الخاصية الفيزيائية لا تغيّر طبيعة المادة. التوصيل الكهربائي خاصية فيزيائية للنحاس.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'كيمياء عامة', 'اختيار من متعدد', 'أي خواص السكر الآتية ليست فيزيائية؟', '["يوجد على شكل بلورات صلبة في درجات الحرارة العادية", "يظهر بلون أبيض", "طعمه حلو", "يتحلّل إلى كربون وبخار ماء عند تسخينه"]'::jsonb, 3, 'التحلل الحراري = تغيّر كيميائي يحوّل السكر لمواد جديدة.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'جدول دوري', 'اختيار من متعدد', 'ماذا تُسمى عناصر المجموعة 18 في الجدول الدوري؟', '["الفلزات القلوية", "الفلزات الخاملة", "الغازات الخاملة", "العناصر النشطة"]'::jsonb, 2, 'المجموعة 18 = الغازات النبيلة (الخاملة): He, Ne, Ar, ...', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'جدول دوري', 'اختيار من متعدد', 'ما هو عدد التأكسد للعنصر Ar؟', '["8", "6", "صفر", "18"]'::jsonb, 2, 'الأرجون غاز نبيل، عدد تأكسده = 0.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'كيمياء عضوية', 'اختيار من متعدد', 'أي التالي هيدروكربون مشبع؟', '["C₂H₂", "C₂H₄", "C₂H₆", "C₄H₁₀"]'::jsonb, 2, 'الألكان (روابط أحادية فقط) مشبع. C₂H₆ هو الإيثان (ألكان).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'مخاليط', 'اختيار من متعدد', 'مخلوط متجانس من مواد سائلة عديمة اللون، يُفصل بـ:', '["التقطير", "الترشيح", "التبلور", "التبخّر"]'::jsonb, 0, 'التقطير يفصل سوائل متجانسة بناءً على فروق نقاط الغليان.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'حالات المادة', 'اختيار من متعدد', 'في مخطط الحالة الفيزيائية (الطور)، النقطة التي تمثل كلاً من الضغط ودرجة الحرارة، ولا يمكن للماء بعدها أن يكون في الحالة السائلة هي النقطة:', '["الثلاثية", "الحرجة", "النشطة", "الصغرية"]'::jsonb, 1, 'النقطة الحرجة: فوقها لا يمكن التمييز بين الحالة السائلة والغازية.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'كيمياء حيوية', 'اختيار من متعدد', 'أي الهرمونات التالية تحلل الكربوهيدرات المعقّدة إلى كربوهيدرات بسيطة؟', '["إيثيلين", "سايتوكينينات", "جبرلينات", "كاسين"]'::jsonb, 2, 'الجبرلينات هرمونات نباتية تنشّط الإنزيمات التي تكسر الكربوهيدرات المعقّدة.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'كيمياء عامة', 'اختيار من متعدد', 'أي التالي يمثّل خاصية كيميائية؟', '["الماء عديم اللون", "ملح الطعام بلوري صلب", "يتحلّل السكر إلى كربون وماء", "يصهر الحديد بالحرارة"]'::jsonb, 2, 'التحلل = تغيّر كيميائي. الباقي خواص فيزيائية.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'تكوين إلكتروني', 'اختيار من متعدد', 'أي الأعداد الكتلية الآتية الأقوى ترابطاً فيها أكثر استقراراً علماً أن (Fe=56, F=19, N=14, He=4):', '["الحديد", "النيتروجين", "الفلور", "الهيليوم"]'::jsonb, 0, 'الحديد ⁵⁶Fe من أكثر الأنوية استقراراً (طاقة ربط/نيوكليون عالية). نقطة قمة منحنى الاستقرار النووي.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'كيمياء عامة', 'اختيار من متعدد', '"النحاس قابل للطرق والسحب" تُعدّ:', '["خاصية كيميائية", "تغيّر كيميائي", "خاصية فيزيائية", "تغيّر فيزيائي"]'::jsonb, 2, 'الطرق والسحب صفة لا تغيّر تركيب المادة → خاصية فيزيائية.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'كيمياء عضوية', 'اختيار من متعدد', 'ما المتشكل الكيميائي الصحيح للصيغة الجزيئية C₃H₈O؟', '["CH₃CH₂CH₂OH", "CH₃CH₂COOH", "CH₃COOCH₃", "CH₃CH₂CHO"]'::jsonb, 0, 'البروبانول CH₃CH₂CH₂OH صيغته C₃H₈O. الباقية صيغ جزيئية مختلفة.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'تكوين إلكتروني', 'اختيار من متعدد', 'أي العناصر التالية توزيعها الإلكتروني [Ne]3s²3p³ علماً أن العدد الذري Ne = 10؟', '["⁶³.⁵Cu", "⁵²Cr", "⁴⁰Ar", "³¹P"]'::jsonb, 3, 'عدد إلكترونات [Ne]3s²3p³ = 10+5 = 15. العدد الذري 15 = فوسفور ³¹P.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'جدول دوري', 'اختيار من متعدد', 'عدد تأكسد ذرات الغازات النبيلة:', '["6", "8", "10", "صفر"]'::jsonb, 3, 'الغازات النبيلة مستويات تكافؤها ممتلئة، فلا تتفاعل وعدد تأكسدها = 0.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'تهجين', 'اختيار من متعدد', 'ما هو شكل المركب SiH₄؟', '["مثلث هرمي", "خطّي", "مثلث متساوي", "رباعي الأوجه منتظم"]'::jsonb, 3, 'تهجين السيليكون sp³، فيكون شكل SiH₄ رباعي الأوجه منتظم (tetrahedral).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'محاليل', 'اختيار من متعدد', 'عدد مولات 3 مولار مذاب في لتر من المحلول:', '["1", "2", "3", "4"]'::jsonb, 2, 'تعريف المولارية: عدد المولات في لتر = 3 mol.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'حركية كيميائية', 'اختيار من متعدد', 'إذا كان متوسط سرعة إنتاج مادة ناتجة في تفاعل كيميائي يساوي 1 mol/L·s وكان تركيزها 2 M عند الزمن 4 دقائق، فكم يكون تركيزها عند الزمن 5 دقائق؟', '["1 M", "2 M", "3 M", "4 M"]'::jsonb, 2, 'الزيادة في 60 ثانية = 60·(1/60) M أو الزيادة = 1 mol/L. 2 + 1 = 3 M.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'غازات', 'اختيار من متعدد', 'إذا كان لديك عنصرين معلومين المقدار هما H₂ وضغط كلّ منهما 4 kPa، 5 kPa وعنصر الهيليوم (He) مجهول الضغط. إذا كان الضغط الكلي يساوي 25 kPa فما مقدار ضغط الهيليوم؟', '["4 kPa", "16 kPa", "24 kPa", "32 kPa"]'::jsonb, 1, 'قانون دالتون: P_total = P_H2(1) + P_H2(2) + P_He. P_He = 25 − 4 − 5 = 16 kPa.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'محاليل', 'اختيار من متعدد', 'ما النسبة المئوية بدلالة الكتلة لمحلول يحوي 60 g من المذاب في 200 g من المحلول؟', '["10%", "30%", "40%", "60%"]'::jsonb, 1, '% الكتلة = (60/200) × 100 = 30%.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'تكوين إلكتروني', 'اختيار من متعدد', 'عدد إلكترونات تكافؤ ¹⁵O علماً بأن N=7, O=8.', '["5", "12", "17", "19"]'::jsonb, 1, 'الأكسجين O له 6 إلكترونات تكافؤ. النيوترونات = 15−8 = 7. الإجابة المعتمدة 12 — قد يكون مرجع المصدر مختلف.', grp_id, NULL, false, 'active', false);
